		// We didn't find it
n33: 		return nil, handlers.InvalidArgumentErrorf(
			"Errors in provided fields.",
			map[string]string{
				"host_id": "The requested host id is not available.",
			})
	}
n34: 	if chosenId == nil {
n35: 		if len(hostIds) == 0 {
			// No hosts were found, error
n36: 			return nil, handlers.NotFoundErrorf("No hosts found from available target host sets.")
		}
n37: 		chosenId = &hostIds[rand.Intn(len(hostIds))]
	}

	// Generate the endpoint URL
n38: 	endpointUrl := &url.URL{
		Scheme: t.GetType(),
	}
n39: 	defaultPort := t.GetDefaultPort()
n40: 	var endpointHost string
n41: 	switch host.SubtypeFromId(chosenId.hostId) {
n42: 	case host.StaticSubtype:
n43: 		h, err := staticHostRepo.LookupHost(ctx, chosenId.hostId)
n44: 		if err != nil {
n45: 			return nil, fmt.Errorf("error looking up host: %w", err)
		}
n46: 		endpointHost = h.Address
n47: 		if endpointHost == "" {
n48: 			return nil, errors.New("host had empty address")
		}
	}
n49: 	if defaultPort != 0 {
n50: 		endpointUrl.Host = fmt.Sprintf("%s:%d", endpointHost, defaultPort)
	} else {
n51: 		endpointUrl.Host = endpointHost
	}

n52: 	expTime := timestamppb.Now()
n53: 	expTime.Seconds += int64(t.GetSessionMaxSeconds())
n54: 	sessionComposition := session.ComposedOf{
		UserId:          authResults.UserId,
		HostId:          chosenId.hostId,
		TargetId:        t.GetPublicId(),
		HostSetId:       chosenId.hostSetId,
		AuthTokenId:     authResults.AuthTokenId,
		ScopeId:         authResults.Scope.Id,
		Endpoint:        endpointUrl.String(),
		ExpirationTime:  &timestamp.Timestamp{Timestamp: expTime},
		ConnectionLimit: t.GetSessionConnectionLimit(),
	}

n55: 	sess, err := session.New(sessionComposition)
n56: 	if err != nil {
n57: 		return nil, err
	}
n58: 	wrapper, err := s.kmsCache.GetWrapper(ctx, authResults.Scope.Id, kms.KeyPurposeSessions)
n59: 	if err != nil {
n60: 		return nil, err
	}
n61: 	sess, privKey, err := sessionRepo.CreateSession(ctx, wrapper, sess)
n62: 	if err != nil {
n63: 		return nil, err
	}

n64: 	var workers []*pb.WorkerInfo
n65: 	servers, err := serversRepo.ListServers(ctx, servers.ServerTypeWorker)
n66: 	if err != nil {
n67: 		return nil, err
	}
n68: 	for _, v := range servers {
n69: 		workers = append(workers, &pb.WorkerInfo{Address: v.Address})
	}

n70: 	sad := &pb.SessionAuthorizationData{
		SessionId:       sess.PublicId,
		TargetId:        t.GetPublicId(),
		Scope:           authResults.Scope,
		CreatedTime:     sess.CreateTime.GetTimestamp(),
		Type:            t.GetType(),
		Certificate:     sess.Certificate,
		PrivateKey:      privKey,
		WorkerInfo:      workers,
		ConnectionLimit: t.GetSessionConnectionLimit(),
	}
n71: 	marshaledSad, err := proto.Marshal(sad)
n72: 	if err != nil {
n73: 		return nil, err
	}
n74: 	encodedMarshaledSad := base58.FastBase58Encoding(marshaledSad)

n75: 	ret := &pb.SessionAuthorization{
		SessionId:          sess.PublicId,
		TargetId:           t.GetPublicId(),
		Scope:              authResults.Scope,
		CreatedTime:        sess.CreateTime.GetTimestamp(),
		Type:               t.GetType(),
		AuthorizationToken: string(encodedMarshaledSad),
		UserId:             authResults.UserId,
		HostId:             chosenId.hostId,
		HostSetId:          chosenId.hostSetId,
	}
n76: 	return &pbs.AuthorizeSessionResponse{Item: ret}, nil
